"import os\n\nroot_dir = r\"c:\\Users\\hp\\Desktop\\AI STEM Lab Assistant\\backend\\app\"\n\nreplacements = {\n    \"from app.routes\": \"from app.core_backend.routes\",\n    \"import app.routes\": \"import app.core_backend.routes\",\n    \"from app.models\": \"from app.core_backend.models\",\n    \"import app.models\": \"import app.core_backend.models\",\n    \"from app.database\": \"from app.core_backend.database\",\n    \"import app.database\": \"import app.core_backend.database\",\n    \"from app.core\": \"from app.core_backend.core\",\n    \"import app.core\": \"import app.core_backend.core\",\n    \"from app.services.tutor_service\": \"from app.ai_agent.tutor_service\",\n    \"import app.services.tutor_service\": \"import app.ai_agent.tutor_service\",\n    \"from app.services.physics_engine\": \"from app.machine_learning.physics_engine\",\n    \"import app.services.physics_engine\": \"import app.machine_learning.physics_engine\",\n    \"from app.services.cv_service\": \"from app.machine_learning.cv_service\",\n    \"import app.services.cv_service\": \"import app.machine_learning.cv_service\",\n    \"from app.services.report_generator\": \"from app.core_backend.report_generator\",\n    \"import app.services.report_generator\": \"import app.core_backend.report_generator\",\n}\n\nfor root, dirs, files in os.walk(root_dir):\n    for file in files:\n        if file.endswith(\".py\"):\n            filepath = os.path.join(root, file)\n            with open(filepath, \"r\", encoding=\"utf-8\") as f:\n                content = f.read()\n                \n            new_content = content\n            for old, new in replacements.items():\n                new_content = new_content.replace(old, new)\n                \n            if new_content != content:\n                with open(filepath, \"w\", encoding=\"utf-8\") as f:\n                    f.write(new_content)\n                print(f\"Updated {filepath}\")\n"